      return c.json({ error: 'الأوردر مش موجود أو مش بتاعك' }, 404)
    }

    // منع المندوب من إلغاء أوردر مش ACCEPTED
    if (status === 'CANCELLED' && order.status !== 'ACCEPTED') {
      return c.json({ error: 'مقدرش تلغي الأوردر في الحالة دي' }, 400)
    }
